function initHeader(){const e=document.getElementById("site-header");if(!e)return;const t=()=>{window.scrollY>10?e.classList.add("scrolled"):e.classList.remove("scrolled")};window.addEventListener("scroll",t,{passive:!0}),t()}function initReadingProgress(){const e=document.getElementById("reading-progress-bar");if(!e)return;const t=()=>{const t=window.scrollY,n=document.documentElement.scrollHeight-window.innerHeight,o=n>0?t/n*100:0;e.style.width=`${Math.min(o,100)}%`};window.addEventListener("scroll",t,{passive:!0}),t()}function initMobileNav(){const e=document.getElementById("mobile-fixed-nav");if(!e)return;const t=e.querySelectorAll('a[href^="#"]:not(.mobile-nav-cta)'),n=[];t.forEach(e=>{const t=e.getAttribute("href").substring(1),o=document.getElementById(t);o&&n.push({link:e,section:o})});const o=()=>{const e=window.scrollY+200;let o=null;n.forEach(({link:t,section:n})=>{const s=n.offsetTop,i=s+n.offsetHeight;e>=s&&e<i&&(o=t)}),t.forEach(e=>e.classList.remove("active")),o&&o.classList.add("active")};window.addEventListener("scroll",o,{passive:!0}),o()}function initFAQ(){document.querySelectorAll(".faq-question").forEach(e=>{e.addEventListener("click",()=>{const t=e.closest(".faq-item"),n=t.classList.contains("active");document.querySelectorAll(".faq-item.active").forEach(e=>{e!==t&&(e.classList.remove("active"),e.querySelector(".faq-question").setAttribute("aria-expanded","false"))}),t.classList.toggle("active"),e.setAttribute("aria-expanded",!n)})})}function initScrollAnimations(){const e=document.querySelectorAll("[data-aos]");if(!e.length)return;const t=new IntersectionObserver(e=>{e.forEach(e=>{if(e.isIntersecting){const n=e.target.dataset.aosDelay||0;setTimeout(()=>{e.target.classList.add("aos-animate")},n),t.unobserve(e.target)}})},{threshold:.1,rootMargin:"0px 0px -50px 0px"});e.forEach((e,n)=>{const o=e.closest(".problems-grid, .service-grid, .cases-grid, .voices-grid, .faq-list");if(o){const t=o.querySelectorAll("[data-aos]"),n=Array.from(t).indexOf(e);e.dataset.aosDelay=80*n}t.observe(e)})}function initParticles(){const e=document.getElementById("hero-particles");if(!e)return;const t=["rgba(230, 57, 70, 0.3)","rgba(255, 140, 66, 0.3)","rgba(255, 255, 255, 0.15)","rgba(230, 57, 70, 0.15)"];for(let n=0;n<20;n++){const n=document.createElement("div");n.classList.add("particle");const o=6*Math.random()+2,s=100*Math.random(),i=15*Math.random()+10,r=15*Math.random(),c=t[Math.floor(Math.random()*t.length)];n.style.width=`${o}px`,n.style.height=`${o}px`,n.style.left=`${s}%`,n.style.bottom="-10px",n.style.background=c,n.style.animationDuration=`${i}s`,n.style.animationDelay=`${r}s`,e.appendChild(n)}}function initSmoothScroll(){document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",t=>{const n=e.getAttribute("href");if("#"===n)return;const o=document.querySelector(n);if(!o)return;t.preventDefault();const s=document.getElementById("site-header")?.offsetHeight||0,i=o.getBoundingClientRect().top+window.scrollY-s;window.scrollTo({top:i,behavior:"smooth"})})})}function initForm(){const e=document.getElementById("contact-form"),t=document.getElementById("submit-btn"),n=document.getElementById("form-success"),o=document.getElementById("privacy-agree");e&&t&&n&&(o&&o.addEventListener("change",()=>{t.disabled=!o.checked}),e.addEventListener("submit",async n=>{if(n.preventDefault(),!o||o.checked)if(e.checkValidity()){t.disabled=!0,t.textContent="送信中...";try{const t=new FormData(e);if(!(await fetch(e.action,{method:"POST",body:t})).ok)throw new Error("送信に失敗しました");"function"==typeof gtag&&gtag("event","generate_lead",{event_category:"form",event_label:"free_diagnosis",monthly_sales:t.get("monthly_sales")||"",desired_services:t.getAll("desired_services[]").join(", ")||""}),setTimeout(()=>{window.location.href="thanks.html"},500)}catch(e){alert("送信に失敗しました。お手数ですが時間をおいてもう一度お試しください。"),t.disabled=!1,t.textContent="▶ 無料の店舗診断を申し込む"}}else e.reportValidity();else alert("個人情報の取り扱いに同意してください。")}))}function initStepForm(){const e=document.querySelectorAll(".step-next-btn"),t=document.querySelectorAll(".step-prev-btn");if(!e.length)return;let n=!1;const o=document.getElementById("monthly-sales");o&&o.addEventListener("change",()=>{n||"function"!=typeof gtag||(gtag("event","form_start",{event_category:"form",event_label:"free_diagnosis"}),n=!0)}),e.forEach(e=>{e.addEventListener("click",()=>{const t=e.closest(".step-form-step"),n=e.dataset.next,s=document.getElementById(`step-${n}`);if("step-1"===t.id){const e=t.querySelector("select");if(e&&!e.value)return e.focus(),void e.reportValidity()}if(t&&s){if("function"==typeof gtag)if("step-1"===t.id)gtag("event","step1_complete",{event_category:"form",event_label:"monthly_sales_selected",monthly_sales:o?o.value:""});else if("step-2"===t.id){const e=Array.from(t.querySelectorAll('input[name="desired_services[]"]:checked')).map(e=>e.value);gtag("event","step2_complete",{event_category:"form",event_label:"desired_services_selected",desired_services:e.join(", ")||"なし"})}t.classList.remove("active"),s.classList.add("active");const e=document.querySelector(".contact-form");if(e){const t=document.getElementById("site-header")?.offsetHeight||0,n=e.getBoundingClientRect().top+window.scrollY-t-16;window.scrollTo({top:n,behavior:"smooth"})}}})}),t.forEach(e=>{e.addEventListener("click",()=>{const t=e.closest(".step-form-step"),n=e.dataset.prev,o=document.getElementById(`step-${n}`);if(t&&o){t.classList.remove("active"),o.classList.add("active");const e=document.querySelector(".contact-form");if(e){const t=document.getElementById("site-header")?.offsetHeight||0,n=e.getBoundingClientRect().top+window.scrollY-t-16;window.scrollTo({top:n,behavior:"smooth"})}}})})}document.addEventListener("DOMContentLoaded",()=>{initHeader(),initReadingProgress(),initMobileNav(),initFAQ(),initScrollAnimations(),initParticles(),initSmoothScroll(),initForm(),initStepForm()});